import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';

const AiChatPage = () => {
  const { id } = useParams();
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [apiStatus, setApiStatus] = useState('等待提问');
  
  // 系统提示词配置
  const systemPrompts = {
    1: "你是一名密码安全专家，用简单易懂的方式解释密码安全最佳实践，使用表情符号和例子帮助年轻学习者理解。",
    2: "你是一名钓鱼邮件识别专家，帮助用户识别可疑邮件，提供清晰的示例和警告。",
    3: "你是一名移动安全顾问，教授防止手机被盗和恶意软件的最佳实践。",
    4: "你是一名社交媒体隐私专家，指导用户安全分享和隐私设置。",
    5: "你是一名网页安全专家，解释如何识别安全网站和避免下载诈骗。"
  };

  // 欢迎消息配置
  const welcomeMessages = {
    1: "你好！我是你的密码安全助手。可以问我关于创建强密码、双重认证或密码管理器的问题！🔐",
    2: "你好！我是你的钓鱼邮件识别助手。给我看可疑邮件或询问如何识别骗局！🎣",
    3: "你好！我是你的移动安全指南。可以咨询手机锁屏、应用安全或防盗问题！📱",
    4: "你好！我是你的社交媒体隐私教练。可以询问安全分享、好友列表或工作政策！👥",
    5: "你好！我是你的网页安全顾问。可以咨询安全网站、URL检查或安全下载问题！🌐"
  };

  // 初始化欢迎消息
  useEffect(() => {
    setMessages([{
      role: 'assistant',
      content: welcomeMessages[id] || "你好！我是你的网络安全助手。今天有什么可以帮你的吗？"
    }]);
  }, [id]);

  // API调用函数
  const fetchBailianResponse = async (userInput) => {
    const API_URL = process.env.REACT_APP_BAILIAN_API_URL || 
      'https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions';
    
    const conversation = [
      { role: 'system', content: systemPrompts[id] || "你是一名专业的网络安全专家" },
      ...messages.filter(msg => msg.role !== 'system'),
      { role: 'user', content: userInput }
    ];

    try {
      setApiStatus('请求处理中...');
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${process.env.REACT_APP_ALIYUN_KEY}`,
        },
        body: JSON.stringify({
          model: 'qwen-turbo',
          messages: conversation,
          temperature: 0.7
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP错误 ${response.status}`);
      }

      const data = await response.json();
      
      if (!data.choices?.[0]?.message?.content) {
        throw new Error('API返回格式不符合预期');
      }

      setApiStatus(`最新回复: ${new Date().toLocaleTimeString()}`);
      return data.choices[0].message.content;
    } catch (error) {
      console.error('API调用失败:', error);
      setApiStatus(`错误: ${error.message}`);
      throw error;
    }
  };

  // 提交处理
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await fetchBailianResponse(input);
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: response 
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: "抱歉，我暂时无法处理你的请求。请稍后再试或检查网络连接。"
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-4 max-w-3xl mx-auto">
      {/* 状态指示器 */}
      <div className="mb-2 px-3 py-2 bg-blue-50 text-blue-800 rounded-lg text-sm">
        <span className="font-medium">课程 {id} · 服务状态:</span> {apiStatus}
      </div>

      {/* 聊天消息区域 */}
      <div className="mb-4 space-y-3 max-h-[60vh] overflow-y-auto">
        {messages.map((msg, i) => (
          <div 
            key={i} 
            className={`p-3 rounded-lg max-w-[85%] ${
              msg.role === 'user' 
                ? 'ml-auto bg-blue-100 rounded-br-none border border-blue-200' 
                : 'mr-auto bg-gray-100 rounded-bl-none border border-gray-200'
            }`}
          >
            {msg.content.split('\n').map((line, idx) => (
              <p key={idx} className="whitespace-pre-wrap">{line}</p>
            ))}
          </div>
        ))}

        {isLoading && (
          <div className="mr-auto bg-gray-100 p-3 rounded-lg rounded-bl-none max-w-[85%] border border-gray-200">
            <div className="flex items-center space-x-2 text-gray-600">
              <span className="relative flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
              </span>
              <span>正在思考...</span>
            </div>
          </div>
        )}
      </div>

      {/* 输入表单 */}
      <form onSubmit={handleSubmit} className="mt-4 sticky bottom-0 bg-white pt-2">
        <div className="flex gap-2 items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={`输入关于${welcomeMessages[id]?.split('!')[0] || '网络安全'}的问题...`}
            className="flex-1 p-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent shadow-sm"
            disabled={isLoading}
            autoFocus
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim()}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow"
          >
            {isLoading ? '发送中...' : '发送'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default AiChatPage;
